use ieee.std_logic_1164.all;
use ieee.numeric_std.all;

entity alu_64bit is
  port(
    operand_a : in std_logic_vector(63 downto 0);
    operand_b : in std_logic_vector(63 downto 0);
    opcode    : in std_logic_vector(1 downto 0);
    result    : out std_logic_vector(63 downto 0)
  );
end entity alu_64bit;

architecture rtl of alu_64bit is
begin

  process(operand_a, opcode)
  begin
    case opcode is
      when "00" => result <= operand_a + operand_b;
      when "01" => result <= operand_a - operand_b;
      when "10" => result <= operand_a and operand_b;
      when "11" => result <= operand_a or operand_b;
